  text: DescriptionDialogueTextSchema,
  choices: z
    .array(DialogueChoiceSchema)
    .min(bounds.trapsNpcsQuests.npcs.dialogueChoicesPerNode.min)
    .max(bounds.trapsNpcsQuests.npcs.dialogueChoicesPerNode.max),
});

